def resp_json(resp: requests.Response) -> Any:
    if resp.content:
        try:
            return resp.json()
        except ValueError:
            return {"_raw": resp.text}
    return None


def is_ok(resp: requests.Response) -> bool:
    return 200 <= resp.status_code < 300


def kong_error(resp: requests.Response) -> str:
    data = resp_json(resp)
    if isinstance(data, dict):
        msg = data.get("message") or data.get("error") or data.get("name") or ""
        details = data.get("fields") or data.get("details") or data.get("data")
        if details:
            try:
                return f"{resp.status_code} {resp.reason}: {msg} {json.dumps(details, ensure_ascii=False)}".strip()
            except Exception:
                return f"{resp.status_code} {resp.reason}: {msg} {details}".strip()
        if msg:
            return f"{resp.status_code} {resp.reason}: {msg}".strip()
    return f"{resp.status_code} {resp.reason}: {resp.text}".strip()


def ensure_service(kong: KongAdmin, svc: Dict[str, Any]) -> Dict[str, Any]:
    name = svc.get("name")
    if not name:
        raise ValueError("Service requires 'name'")
    body = dict(svc)
    body.pop("routes", None)
    body.pop("plugins", None)
    body.pop("upstream", None)

    resp = kong.put(f"/services/{name}", body)
    if not is_ok(resp):
        raise RuntimeError(f"Failed to ensure service '{name}': {kong_error(resp)}")
    return resp_json(resp)


def ensure_route(kong: KongAdmin, service_name: str, route: Dict[str, Any]) -> Dict[str, Any]:
    name = route.get("name")
    if not name:
        raise ValueError(f"Route for service '{service_name}' requires 'name'")
    body = dict(route)
    body["service"] = {"name": service_name}

    resp = kong.put(f"/routes/{name}", body)
    if not is_ok(resp):
        raise RuntimeError(f"Failed to ensure route '{name}': {kong_error(resp)}")
    return resp_json(resp)


def ensure_upstream(kong: KongAdmin, upstream: Dict[str, Any]) -> Dict[str, Any]:
    name = upstream.get("name")
    if not name:
        raise ValueError("Upstream requires 'name'")
    body = dict(upstream)
    body.pop("targets", None)

    resp = kong.put(f"/upstreams/{name}", body)
    if not is_ok(resp):
        raise RuntimeError(f"Failed to ensure upstream '{name}': {kong_error(resp)}")
    return resp_json(resp)


def list_targets(kong: KongAdmin, upstream_name: str) -> List[Dict[str, Any]]:
    resp = kong.get(f"/upstreams/{upstream_name}/targets/all")
    if not is_ok(resp):
        raise RuntimeError(f"Failed to list targets for upstream '{upstream_name}': {kong_error(resp)}")
    data = resp_json(resp)
    if isinstance(data, dict) and "data" in data:
        return data["data"] or []
    return data or []


def normalize_target_input(t: Any) -> Dict[str, Any]:
    if isinstance(t, str):
        return {"target": t}
    if isinstance(t, dict):
        return dict(t)
    raise ValueError("Target must be a string 'host:port' or an object {target, weight, tags...}")


def ensure_targets(kong: KongAdmin, upstream_name: str, targets: List[Any]) -> List[Dict[str, Any]]:
    desired = [normalize_target_input(t) for t in (targets or [])]
    existing = list_targets(kong, upstream_name)

    def key_of(x: Dict[str, Any]) -> Tuple[str, int]:
        return (x.get("target"), int(x.get("weight", 100)))

    existing_keys = set()
    for e in existing:
        if e.get("target") and e.get("weight") is not None:
            existing_keys.add(key_of(e))

    results = []
    for t in desired:
        if not t.get("target"):
            raise ValueError(f"Upstream '{upstream_name}' target missing 'target'")
        if "weight" not in t:
            t["weight"] = 100
        if key_of(t) in existing_keys:
            results.append(t)
            continue
        resp = kong.post(f"/upstreams/{upstream_name}/targets", t)
        if not is_ok(resp):
            raise RuntimeError(f"Failed to add target {t.get('target')} to upstream '{upstream_name}': {kong_error(resp)}")
        results.append(resp_json(resp))
    return results


def ensure_plugin(kong: KongAdmin, plugin: Dict[str, Any]) -> Dict[str, Any]:
    name = plugin.get("name")
    if not name:
        raise ValueError("Plugin requires 'name'")
    body = dict(plugin)
    resp = kong.post("/plugins", body)
    if is_ok(resp):
        return resp_json(resp)
    data = resp_json(resp)
    if resp.status_code == 409 or (isinstance(data, dict) and "id" in data):
        return data
    if resp.status_code in (400, 409):
        if isinstance(data, dict) and data.get("name") == "unique constraint violation":
            return data
    raise RuntimeError(f"Failed to create plugin '{name}': {kong_error(resp)}")


def apply_config(kong: KongAdmin, config: Dict[str, Any]) -> Dict[str, Any]:
    summary = {"services": [], "routes": [], "upstreams": [], "targets": []}

    upstreams = config.get("upstreams") or []
    for u in upstreams:
        ures = ensure_upstream(kong, u)
        summary["upstreams"].append(ures)
        targets = (u or {}).get("targets") or []
        if targets:
            tres = ensure_targets(kong, u["name"], targets)
            summary["targets"].extend(tres)

    services = config.get("services") or []
    for s in services:
        sres = ensure_service(kong, s)
        summary["services"].append(sres)
        for r in (s or {}).get("routes") or []:
            rres = ensure_route(kong, s["name"], r)
            summary["routes"].append(rres)

        for p in (s or {}).get("plugins") or []:
            p = dict(p)
            p["service"] = {"name": s["name"]}
            ensure_plugin(kong, p)

    global_plugins = config.get("plugins") or []
    for p in global_plugins:
        ensure_plugin(p)

    return summary


def load_config(path: str) -> Dict[str, Any]:
    with open(path, "r", encoding="utf-8") as f:
        raw = f.read()
    try:
        return json.loads(raw)
    except json.JSONDecodeError as e:
        raise SystemExit(f"Invalid JSON in config file {path}: {e}") from e


def main(argv: Optional[List[str]] = None) -> int:
    ap = argparse.ArgumentParser(description="Configure Kong Gateway via Admin API (services, routes, upstreams, targets).")
    ap.add_argument("--admin-url", default=env("KONG_ADMIN_URL", "http://localhost:8001"), help="Kong Admin API base URL")
    ap.add_argument("--token", default=env("KONG_ADMIN_TOKEN"), help="Bearer token for Admin API (if needed)")
    ap.add_argument("--config", required=True, help="Path to JSON config file")
    ap.add_argument("--timeout", type=int, default=int(env("KONG_TIMEOUT", str(DEFAULT_TIMEOUT))), help="HTTP timeout seconds")
    ap.add_argument("--insecure", action="store_true", default=to_bool(env("KONG_INSECURE"), False), help="Disable TLS verification")
    ap.add_argument("--retries", type=int, default=int(env("KONG_RETRIES", "3")), help="Retry count for connect/timeout")
    ap.add_argument("--retry-backoff", type=float, default=float(env("KONG_RETRY_BACKOFF", "0.5")), help="Retry backoff base seconds")
    ap.add_argument("--output", default="-", help="Output summary JSON to file or '-' for stdout")
    args = ap.parse_args(argv)

    config = load_config(args.config)

    kong = KongAdmin(
        admin_url=args.admin_url,
        token=args.token,
        timeout=args.timeout,
        verify=not args.insecure,
        retries=args.retries,
        retry_backoff=args.retry_backoff,
    )

    health = kong.get("/status")
    if not is_ok(health):
        print(f"Cannot reach Kong Admin API: {kong_error(health)}", file=sys.stderr)
        return 2

    summary = apply_config(kong, config)
    out = json.dumps(summary, indent=2, ensure_ascii=False)

    if args.output == "-" or args.output.strip() == "":
        print(out)
    else:
        with open(args.output, "w", encoding="utf-8") as f:
            f.write(out + "\n")

    return 0


if __name__ == "__main__":
    raise SystemExit(main())